args.sparql:
SELECT ?characterLabel WHERE {
  wd:Q13417189 p:P161 ?cast.
  ?cast pq:P453 ?character.
  ?character rdfs:label ?characterLabel.
  FILTER(LANG(?characterLabel) = "en")
}

SELECT ?actor ?actorLabel WHERE {
  wd:Q13417189 p:P161 ?cast.
  ?cast ps:P161 ?actor;
        pq:P453 ?role.
  ?role rdfs:label ?roleLabel.
  ?actor rdfs:label ?actorLabel.
  FILTER(LANG(?roleLabel) = "en" && STR(?roleLabel) = "Joseph Cooper")
  FILTER(LANG(?actorLabel) = "en")
}

SELECT ?actor ?actorLabel WHERE {
  wd:Q13417189 p:P161 ?cast.
  ?cast ps:P161 ?actor;
        pq:P453 ?role.
  ?role rdfs:label ?roleLabel.
  ?actor rdfs:label ?actorLabel.
  FILTER(LANG(?roleLabel) = "en" && STR(?roleLabel) = "Joseph Cooper")
  FILTER(LANG(?actorLabel) = "en")
}
